/**
 * Harness Orchestrator
 *
 * AI Project Manager that orchestrates multiple Claude agents
 * to complete harness tasks in parallel.
 */

export * from './types.js';
export { DependencyGraph } from './graph/DependencyGraph.js';
export { CriticalPath } from './graph/CriticalPath.js';
export { TaskScheduler } from './scheduler/TaskScheduler.js';
export { PriorityQueue } from './scheduler/PriorityQueue.js';
export { AgentPool } from './agents/AgentPool.js';
export { ClaudeAgent } from './agents/ClaudeAgent.js';
export { StateManager } from './state/StateManager.js';
export { FileLock } from './state/FileLock.js';
export { AIManager } from './ai/AIManager.js';
export { Orchestrator } from './orchestrator/Orchestrator.js';
export { Dashboard } from './dashboard/Dashboard.js';
export { GitManager } from './verification/GitManager.js';
export { Verifier } from './verification/Verifier.js';

// Visual Testing Integration (O018)
export * from './testing/VisualTesting.js';

// Commit Workflow Enforcement (O019)
export * from './workflow/CommitWorkflow.js';

// Hook Templates
export * from './hooks/HookTemplates.js';

