     1→#!/usr/bin/env node
     2→/**
     3→ * Harness Orchestrator CLI
     4→ *
     5→ * Command-line interface for the harness orchestrator.
     6→ */
     7→
     8→import { Command } from 'commander';
     9→import chalk from 'chalk';
    10→import ora from 'ora';
    11→import { readFileSync } from 'node:fs';
    12→import { resolve } from 'node:path';
    13→
    14→import { DependencyGraph } from '../graph/DependencyGraph.js';
    15→import { CriticalPath } from '../graph/CriticalPath.js';
    16→import { StateManager } from '../state/StateManager.js';
    17→import { AIManager } from '../ai/AIManager.js';
    18→import { Orchestrator } from '../orchestrator/Orchestrator.js';
    19→import { Dashboard } from '../dashboard/Dashboard.js';
    20→import { Verifier } from '../verification/Verifier.js';
    21→import {
    22→  getAllHookTemplates,
    23→  getSettingsTemplate,
    24→} from '../hooks/HookTemplates.js';
    25→import {
    26→  generateVisualTestCommands,
    27→  generateQAChecklist,
    28→  requiresVisualTesting,
    29→  getMcpConfig,
    30→} from '../testing/VisualTesting.js';
    31→import {
    32→  checkFeatureReadyForCommit,
    33→  formatCommitWorkflowCheck,
    34→  generateGitCommitCommand,
    35→  getStagedFiles,
    36→  getUnstagedFiles,
    37→  getUntrackedFiles,
    38→} from '../workflow/CommitWorkflow.js';
    39→import type { HarnessConfig, ModelType } from '../types.js';
    40→
    41→const program = new Command();
    42→
    43→program
    44→  .name('harness')
    45→  .alias('h')
    46→  .description('AI Project Manager for harness task orchestration')
    47→  .version('0.1.0');
    48→
    49→// Default features path
    50→const DEFAULT_FEATURES_PATH = 'features.json';
    51→
    52→/**
    53→ * Resolve features path, using default if not provided
    54→ */
    55→function resolveFeaturesPath(path?: string): string {
    56→  return resolve(path || DEFAULT_FEATURES_PATH);
    57→}
    58→
    59→// Analyze command
    60→program
    61→  .command('analyze [features-path]')
    62→  .description('Analyze dependency graph and show execution plan')
    63→  .action((featuresPath?: string) => {
    64→    const resolvedPath = resolveFeaturesPath(featuresPath);
    65→    const content = readFileSync(resolvedPath, 'utf-8');
    66→    const config: HarnessConfig = JSON.parse(content);
    67→
    68→    const graph = new DependencyGraph(config);
    69→    const criticalPath = new CriticalPath(graph);
    70→
    71→    console.log(chalk.bold('\n📊 Dependency Analysis\n'));
    72→
    73→    // Check for cycles
    74→    const cycle = graph.detectCycles();
    75→    if (cycle) {
    76→      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
    77→      process.exit(1);
    78→    }
    79→    console.log(chalk.green('✓ No cycles detected\n'));
    80→
    81→    // Show features by status
    82→    const pending = graph.getPendingFeatures();
    83→    const completed = graph.getAllFeatures().filter((f) => f.passes);
    84→
    85→    console.log(chalk.bold('Status:'));
    86→    console.log(`  Completed: ${chalk.green(completed.length)}`);
    87→    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    88→    console.log();
    89→
    90→    // Show ready tasks
    91→    const ready = graph.getReadyTasks();
    92→    console.log(chalk.bold('Ready to run (parallelizable):'));
    93→    if (ready.length === 0) {
    94→      console.log(chalk.dim('  None'));
    95→    } else {
    96→      for (const f of ready) {
    97→        const priority = criticalPath.getPriorityScore(f.id);
    98→        const onCritical = criticalPath.getCriticalPath().includes(f.id);
    99→        const critical = onCritical ? chalk.red(' [CRITICAL]') : '';
   100→        console.log(`  ${chalk.cyan(f.id)}: ${f.description}${critical} (priority: ${priority})`);
   101→      }
   102→    }
   103→    console.log();
   104→
   105→    // Show critical path
   106→    const path = criticalPath.getCriticalPath();
   107→    console.log(chalk.bold('Critical Path:'));
   108→    console.log(`  ${path.map((id) => chalk.red(id)).join(' → ')}`);
   109→    console.log();
   110→
   111→    // Show execution order
   112→    const order = graph.topologicalSort();
   113→    console.log(chalk.bold('Topological Order:'));
   114→    console.log(`  ${order.map((id) => graph.getFeature(id)?.passes ? chalk.green(id) : chalk.yellow(id)).join(' → ')}`);
   115→  });
   116→
   117→// Status command
   118→program
   119→  .command('status [features-path]')
   120→  .description('Show current progress status')
   121→  .action((featuresPath?: string) => {
   122→    const resolvedPath = resolveFeaturesPath(featuresPath);
   123→    const stateManager = new StateManager(resolvedPath);
   124→    const aiManager = new AIManager();
   125→
   126→    const config = stateManager.load();
   127→    const progress = stateManager.getProgress();
   128→
   129→    console.log(chalk.bold('\n📈 Harness Status\n'));
   130→    console.log(`Project: ${chalk.cyan(config.project)}`);
   131→    console.log(`Version: ${config.version}`);
   132→    console.log(`Last Updated: ${config.lastUpdated}`);
   133→    console.log();
   134→
   135→    // Progress bar
   136→    const pct = Math.round((progress.completed / progress.total) * 100);
   137→    const filled = Math.round(pct / 5);
   138→    const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);
   139→    console.log(`Progress: [${bar}] ${pct}%`);
   140→    console.log(`  ${chalk.green(progress.completed)} completed / ${chalk.yellow(progress.pending)} pending`);
   141→    console.log();
   142→
   143→    // Features list
   144→    console.log(chalk.bold('Features:'));
   145→    for (const f of config.features) {
   146→      const status = f.passes ? chalk.green('✓') : chalk.yellow('○');
   147→      const blockedBy = f.blockedBy
   148→        ? chalk.dim(` (blocked by: ${Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy})`)
   149→        : '';
   150→      console.log(`  ${status} ${f.id}: ${f.description}${blockedBy}`);
   151→    }
   152→
   153→    // AI summary
   154→    console.log('\n' + aiManager.generateProgressSummary(config.features));
   155→  });
   156→
   157→// Orchestrate command
   158→program
   159→  .command('orchestrate [features-path]')
   160→  .description('Run full orchestration with parallel agents')
   161→  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
   162→  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
   163→  .option('--dry-run', 'Show plan without executing')
   164→  .option('--timeout <ms>', 'Timeout per task in milliseconds', '600000')
   165→  .option('-d, --dashboard', 'Enable real-time dashboard UI')
   166→  .option('--no-costs', 'Disable cost estimates in dashboard')
   167→  .action(async (featuresPath: string | undefined, options) => {
   168→    const spinner = ora('Loading harness configuration...').start();
   169→
   170→    try {
   171→      const resolvedPath = resolveFeaturesPath(featuresPath);
   172→      const stateManager = new StateManager(resolvedPath);
   173→      const config = stateManager.load();
   174→
   175→      spinner.succeed('Configuration loaded');
   176→
   177→      const pending = config.features.filter((f) => !f.passes).length;
   178→
   179→      if (options.dryRun) {
   180→        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
   181→        console.log('Would orchestrate with:');
   182→        console.log(`  Max agents: ${options.maxAgents}`);
   183→        console.log(`  Model: ${options.model}`);
   184→        console.log(`  Features: ${pending} pending`);
   185→        console.log(`  Dashboard: ${options.dashboard ? 'enabled' : 'disabled'}`);
   186→        return;
   187→      }
   188→
   189→      if (pending === 0) {
   190→        console.log(chalk.green('\n✅ All features are already complete!'));
   191→        return;
   192→      }
   193→
   194→      const orchestrator = new Orchestrator(resolvedPath, {
   195→        maxAgents: parseInt(options.maxAgents, 10),
   196→        model: options.model as ModelType,
   197→        timeout: parseInt(options.timeout, 10),
   198→      });
   199→
   200→      if (options.dashboard) {
   201→        // Use real-time dashboard
   202→        const dashboard = new Dashboard(config, {
   203→          liveRefresh: true,
   204→          showCosts: options.costs !== false,
   205→          maxAgents: parseInt(options.maxAgents, 10),
   206→        });
   207→        dashboard.setModel(options.model as 'haiku' | 'sonnet' | 'opus');
   208→        dashboard.attach(orchestrator);
   209→
   210→        const result = await orchestrator.run();
   211→        dashboard.renderFinalSummary();
   212→
   213→        if (result.failed > 0) {
   214→          process.exit(1);
   215→        }
   216→      } else {
   217→        // Classic output mode
   218→        console.log(chalk.bold('\n🚀 Starting Orchestration\n'));
   219→        console.log(`  Max agents: ${chalk.cyan(options.maxAgents)}`);
   220→        console.log(`  Model: ${chalk.cyan(options.model)}`);
   221→        console.log(`  Pending: ${chalk.yellow(pending)} features`);
   222→        console.log();
   223→
   224→        // Event handlers for progress display
   225→        orchestrator.on('taskDispatched', ({ taskId, feature }) => {
   226→          console.log(chalk.blue(`▶ Started ${taskId}: ${feature.description}`));
   227→        });
   228→
   229→        orchestrator.on('taskSucceeded', ({ taskId }) => {
   230→          console.log(chalk.green(`✓ Completed ${taskId}`));
   231→        });
   232→
   233→        orchestrator.on('taskFailed', ({ taskId, error }) => {
   234→          console.log(chalk.red(`✗ Failed ${taskId}: ${error}`));
   235→        });
   236→
   237→        orchestrator.on('deadlock', ({ pending }) => {
   238→          console.log(chalk.red(`\n⚠️  Deadlock detected! ${pending} tasks stuck.`));
   239→        });
   240→
   241→        orchestrator.on('shutdown', ({ signal }) => {
   242→          console.log(chalk.yellow(`\n⚠️  Received ${signal}, shutting down gracefully...`));
   243→        });
   244→
   245→        const runSpinner = ora('Running orchestration...').start();
   246→        const result = await orchestrator.run();
   247→        runSpinner.stop();
   248→
   249→        console.log(chalk.bold('\n📊 Results\n'));
   250→        console.log(`  Completed: ${chalk.green(result.completed)}`);
   251→        console.log(`  Failed: ${chalk.red(result.failed)}`);
   252→
   253→        if (result.failed === 0) {
   254→          console.log(chalk.green('\n✅ Orchestration completed successfully!'));
   255→        } else {
   256→          console.log(chalk.yellow(`\n⚠️  ${result.failed} task(s) failed.`));
   257→          process.exit(1);
   258→        }
   259→      }
   260→    } catch (error) {
   261→      spinner.fail('Orchestration failed');
   262→      console.error(error);
   263→      process.exit(1);
   264→    }
   265→  });
   266→
   267→// Dashboard command (standalone)
   268→program
   269→  .command('dashboard [features-path]')
   270→  .description('Show real-time dashboard (attaches to running orchestration)')
   271→  .option('--no-costs', 'Disable cost estimates')
   272→  .action((featuresPath: string | undefined, options) => {
   273→    const resolvedPath = resolveFeaturesPath(featuresPath);
   274→    const stateManager = new StateManager(resolvedPath);
   275→    const config = stateManager.load();
   276→
   277→    const dashboard = new Dashboard(config, {
   278→      liveRefresh: false,
   279→      showCosts: options.costs !== false,
   280→    });
   281→
   282→    dashboard.render();
   283→  });
   284→
   285→// Verify command
   286→program
   287→  .command('verify [features-path]')
   288→  .description('Verify feature completion and show verification status')
   289→  .option('-f, --feature <id>', 'Verify a specific feature')
   290→  .option('--all', 'Verify all completed features')
   291→  .action(async (featuresPath: string | undefined, options) => {
   292→    const resolvedPath = resolveFeaturesPath(featuresPath);
   293→    const verifier = new Verifier(resolvedPath);
   294→    const stateManager = new StateManager(resolvedPath);
   295→    const config = stateManager.load();
   296→
   297→    console.log(chalk.bold('\n🔍 Feature Verification\n'));
   298→
   299→    // Get git status
   300→    const gitStatus = verifier.getGitStatus();
   301→    if (gitStatus) {
   302→      console.log(chalk.bold('Git Status:'));
   303→      console.log(`  Branch: ${chalk.cyan(gitStatus.branch)}`);
   304→      console.log(`  Clean: ${gitStatus.isClean ? chalk.green('Yes') : chalk.yellow('No')}`);
   305→      if (gitStatus.ahead > 0 || gitStatus.behind > 0) {
   306→        console.log(`  Ahead: ${gitStatus.ahead}, Behind: ${gitStatus.behind}`);
   307→      }
   308→      console.log();
   309→    }
   310→
   311→    // List feature branches
   312→    const branches = verifier.listFeatureBranches();
   313→    if (branches.length > 0) {
   314→      console.log(chalk.bold('Feature Branches:'));
   315→      for (const branch of branches) {
   316→        const status = branch.isMerged ? chalk.green('merged') : chalk.yellow('pending');
   317→        console.log(`  ${branch.name} (${branch.featureId}) - ${status}`);
   318→      }
   319→      console.log();
   320→    }
   321→
   322→    // Verify features
   323→    const featuresToVerify = options.feature
   324→      ? config.features.filter(f => f.id === options.feature)
   325→      : options.all
   326→        ? config.features.filter(f => f.passes)
   327→        : config.features.filter(f => f.passes).slice(0, 5);
   328→
   329→    if (featuresToVerify.length === 0) {
   330→      console.log(chalk.dim('No features to verify'));
   331→      return;
   332→    }
   333→
   334→    console.log(chalk.bold('Verification Results:'));
   335→    for (const feature of featuresToVerify) {
   336→      const result = await verifier.verifyFeature(feature);
   337→      const icon = result.passed ? chalk.green('✓') : chalk.red('✗');
   338→      console.log(`\n${icon} ${chalk.bold(result.featureId)}: ${feature.description}`);
   339→      for (const check of result.checks) {
   340→        const checkIcon = check.passed ? chalk.green('✓') : chalk.red('✗');
   341→        console.log(`    ${checkIcon} ${check.name}: ${chalk.dim(check.details || '')}`);
   342→      }
   343→    }
   344→  });
   345→
   346→// Rollback command
   347→program
   348→  .command('rollback [features-path]')
   349→  .description('Rollback a feature to its previous state')
   350→  .requiredOption('-f, --feature <id>', 'Feature ID to rollback')
   351→  .option('--delete-remote', 'Also delete remote branch')
   352→  .action(async (featuresPath: string | undefined, options) => {
   353→    const resolvedPath = resolveFeaturesPath(featuresPath);
   354→    const verifier = new Verifier(resolvedPath);
   355→    const stateManager = new StateManager(resolvedPath);
   356→
   357→    const featureId = options.feature.toUpperCase();
   358→
   359→    console.log(chalk.bold(`\n🔄 Rolling back feature ${featureId}\n`));
   360→
   361→    const gitStatus = verifier.getGitStatus();
   362→    if (!gitStatus) {
   363→      console.log(chalk.red('Not a git repository. Cannot rollback.'));
   364→      process.exit(1);
   365→    }
   366→
   367→    const branches = verifier.listFeatureBranches();
   368→    const branch = branches.find(b => b.featureId === featureId);
   369→
   370→    if (!branch) {
   371→      console.log(chalk.yellow(`No branch found for feature ${featureId}`));
   372→      console.log('Available feature branches:');
   373→      for (const b of branches) {
   374→        console.log(`  - ${b.name} (${b.featureId})`);
   375→      }
   376→      return;
   377→    }
   378→
   379→    console.log(`Branch: ${chalk.cyan(branch.name)}`);
   380→    console.log(`Merged: ${branch.isMerged ? chalk.green('Yes') : chalk.yellow('No')}`);
   381→    console.log();
   382→
   383→    // Update state to mark as not complete
   384→    const config = stateManager.load();
   385→    const feature = config.features.find(f => f.id === featureId);
   386→    if (feature) {
   387→      feature.passes = false;
   388→      await stateManager.save(config);
   389→      console.log(chalk.green(`✓ Marked ${featureId} as incomplete in features.json`));
   390→    }
   391→
   392→    // Note: In a real implementation, we'd use the GitManager to delete the branch
   393→    console.log(chalk.dim(`To delete the branch manually: git branch -D ${branch.name}`));
   394→
   395→    console.log(chalk.green('\n✓ Rollback complete'));
   396→  });
   397→
   398→// Branches command
   399→program
   400→  .command('branches [features-path]')
   401→  .description('List and manage feature branches')
   402→  .option('--cleanup', 'Delete merged feature branches')
   403→  .action((featuresPath: string | undefined, options) => {
   404→    const resolvedPath = resolveFeaturesPath(featuresPath);
   405→    const verifier = new Verifier(resolvedPath);
   406→
   407→    const gitStatus = verifier.getGitStatus();
   408→    if (!gitStatus) {
   409→      console.log(chalk.red('Not a git repository.'));
   410→      process.exit(1);
   411→    }
   412→
   413→    console.log(chalk.bold('\n🌿 Feature Branches\n'));
   414→    console.log(`Current branch: ${chalk.cyan(gitStatus.branch)}`);
   415→    console.log();
   416→
   417→    const branches = verifier.listFeatureBranches();
   418→
   419→    if (branches.length === 0) {
   420→      console.log(chalk.dim('No feature branches found'));
   421→      return;
   422→    }
   423→
   424→    const merged = branches.filter(b => b.isMerged);
   425→    const pending = branches.filter(b => !b.isMerged);
   426→
   427→    if (pending.length > 0) {
   428→      console.log(chalk.bold('Pending (not merged):'));
   429→      for (const branch of pending) {
   430→        console.log(`  ${chalk.yellow('○')} ${branch.name} (${branch.featureId})`);
   431→      }
   432→      console.log();
   433→    }
   434→
   435→    if (merged.length > 0) {
   436→      console.log(chalk.bold('Merged:'));
   437→      for (const branch of merged) {
   438→        console.log(`  ${chalk.green('✓')} ${branch.name} (${branch.featureId})`);
   439→      }
   440→      console.log();
   441→    }
   442→
   443→    if (options.cleanup && merged.length > 0) {
   444→      console.log(chalk.bold('Cleaning up merged branches...'));
   445→      const deleted = verifier.cleanupMergedBranches();
   446→      console.log(chalk.green(`✓ Deleted ${deleted.length} branch(es)`));
   447→    } else if (merged.length > 0) {
   448→      console.log(chalk.dim(`Run with --cleanup to delete ${merged.length} merged branch(es)`));
   449→    }
   450→  });
   451→
   452→// Init command - bootstrap a new harness project
   453→program
   454→  .command('init [project-path]')
   455→  .description('Initialize a new harness project with standard structure')
   456→  .option('-n, --name <name>', 'Project name')
   457→  .option('--no-hooks', 'Skip generating hooks')
   458→  .option('--no-git', 'Skip git initialization')
   459→  .action(async (projectPath: string | undefined, options) => {
   460→    const targetDir = resolve(projectPath || '.');
