  /**
   * Check if init.sh exists (warning if missing, not error)
   */
  checkInitSh(): CheckResult {
    const initShPath = join(this.projectPath, 'init.sh');

    if (!existsSync(initShPath)) {
      return {
        name: 'init.sh',
        passed: true,
        message: 'init.sh not found (optional but recommended)',
        severity: 'warning',
