program
  .command('rollback [features-path]')
  .description('Rollback a feature to its previous state')
  .requiredOption('-f, --feature <id>', 'Feature ID to rollback')
  .option('--delete-remote', 'Also delete remote branch')
  .action(async (featuresPath: string | undefined, options) => {
    const resolvedPath = resolveFeaturesPath(featuresPath);
    const verifier = new Verifier(resolvedPath);
    const stateManager = new StateManager(resolvedPath);

    const featureId = options.feature.toUpperCase();

    console.log(chalk.bold(`\n🔄 Rolling back feature ${featureId}\n`));

    const gitStatus = verifier.getGitStatus();
    if (!gitStatus) {
      console.log(chalk.red('Not a git repository. Cannot rollback.'));
      process.exit(1);
    }

    const branches = verifier.listFeatureBranches();
    const branch = branches.find(b => b.featureId === featureId);

    if (!branch) {
      console.log(chalk.yellow(`No branch found for feature ${featureId}`));
      console.log('Available feature branches:');
      for (const b of branches) {
        console.log(`  - ${b.name} (${b.featureId})`);
      }
      return;
    }

    console.log(`Branch: ${chalk.cyan(branch.name)}`);
    console.log(`Merged: ${branch.isMerged ? chalk.green('Yes') : chalk.yellow('No')}`);
    console.log();

    // Update state to mark as not complete
    const config = stateManager.load();
    const feature = config.features.find(f => f.id === featureId);
    if (feature) {
      feature.passes = false;
      await stateManager.save(config);
      console.log(chalk.green(`✓ Marked ${featureId} as incomplete in features.json`));
    }

    // Note: In a real implementation, we'd use the GitManager to delete the branch
    console.log(chalk.dim(`To delete the branch manually: git branch -D ${branch.name}`));

    console.log(chalk.green('\n✓ Rollback complete'));
  });

